INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100310, "闇属性ボーナス特大アップ", 16, "闇属性のキャラが４体以上編成されているとき、キャラの属性ボーナスが強化される。闇属性以外の属性ボーナスを無効化する。", 10031001);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100310, "ダメージ減衰", 18, "すべてのモンスターが一度の行動で受けるダメージ値を減衰させる。ダメージ値が上昇するほど減衰率も上昇する。", 10031002);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100310, "物理防御力（ダウン不可）アップ", "boss_def_lower_limit", "バトル開始時、すべてのモンスターの物理防御力を大アップさせる。この効果は物理防御力ダウンの影響を受けない。", 10031003);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100310, "魔法防御力（ダウン不可）アップ", "boss_magic_def_lower_limit", "バトル開始時、すべてのモンスターの魔法防御力を大アップさせる。この効果は魔法防御力ダウンの影響を受けない。", 10031004);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100310, "ＴＰダウンカット", "boss_tp_down_cut", "バトル開始時、すべてのモンスターがＴＰダウン\n75％カット状態になる。", 10031005);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100310, "ＴＰ上昇ダウン", 3, "バトル開始時、すべてのキャラのＴＰ上昇を中ダウンさせる。", 10031006);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100310, "ＨＰ吸収ダウン", 9, "バトル開始時、すべてのキャラのＨＰ吸収を特大ダウンさせる。", 10031007);
